#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 105
#define MAXN 20
#define MAXM 20

char grid[MAXN][MAXM];
int n, m;
int dir[][2] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
char command[MAX];

void bfs(int x, int y) {
    int queue[MAXN*MAXM][2];
    int front = 0, rear = 0;
    queue[rear][0] = x;
    queue[rear++][1] = y;
    while (front < rear) {
        x = queue[front][0];
        y = queue[front++][1];
        for (int i = 0; i < 4; i++) {
            int nx = x + dir[i][0];
            int ny = y + dir[i][1];
            if (nx >= 0 && nx < n && ny >= 0 && ny < m && grid[nx][ny] != '*') {
                if (grid[nx][ny] == 'C') {
                    // found the capital city
                    return;
                }
                queue[rear][0] = nx;
                queue[rear++][1] = ny;
            }
        }
    }
}

int main() {
    scanf("%d %d", &n, &m);
    for (int i = 0; i < n; i++) {
        scanf("%s", grid[i]);
    }
    // find the capital city
